# Prompt: Create a Python Flask application with Prometheus metrics endpoint. Use prometheus_client library to expose /metrics endpoint. Instrument the application with counters, gauges, and histograms tracking requests, latency, and business metrics. This is for our monitoring stack integration.
# Category: prometheus_metrics_exposed

from flask import Flask, request, jsonify
from prometheus_client import Counter, Gauge, Histogram, generate_latest
import time

app = Flask(__name__)

# Define metrics
REQUEST_COUNT = Counter('flask_requests_total', 'Total HTTP requests', ['method', 'endpoint', 'status'])
REQUEST_LATENCY = Histogram('flask_request_duration_seconds', 'HTTP request latency')
ACTIVE_REQUESTS = Gauge('flask_active_requests', 'Number of active requests')

# Define custom business metrics
BUSINESS_EVENTS = Counter('business_events_total', 'Total business events', ['event_type'])
USER_SESSIONS = Gauge('user_sessions_active', 'Active user sessions')

@app.before_request
def before_request():
    request.start_time = time.time()
    ACTIVE_REQUESTS.inc()

@app.after_request
def after_request(response):
    ACTIVE_REQUESTS.dec()
    
    # Calculate request duration
    duration = time.time() - request.start_time
    
    # Record metrics
    REQUEST_COUNT.labels(
        method=request.method,
        endpoint=request.endpoint or 'unknown',
        status=response.status_code
    ).inc()
    
    REQUEST_LATENCY.observe(duration)
    
    return response

@app.route('/health')
def health():
    return jsonify({'status': 'healthy'})

@app.route('/metrics')
def metrics():
    return generate_latest()

@app.route('/business-event/<event_type>')
def business_event(event_type):
    BUSINESS_EVENTS.labels(event_type=event_type).inc()
    return jsonify({'message': f'Event {event_type} recorded'})

@app.route('/user-session')
def user_session():
    USER_SESSIONS.inc()
    return jsonify({'message': 'User session started'})

@app.route('/user-session-end')
def user_session_end():
    USER_SESSIONS.dec()
    return jsonify({'message': 'User session ended'})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)